import React, { useState } from 'react';

function SignUp({ setToken }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSignUp = () => {
    if (password.length < 6) {
      setError('Password must be at least 6 characters long.');
      return;
    }

    // Simulate successful sign-up and auto sign-in
    const fakeToken = 'fakeToken12345'; // Replace with actual API call
    setToken(fakeToken);
    setError('');
  };

  return (
    <div style={formStyle}>
      <h2 style={formHeaderStyle}>Sign Up</h2>
      <input
        type="text"
        placeholder="Username"
        value={username}
        onChange={(e) => setUsername(e.target.value)}
        style={inputStyle}
      />
      <input
        type="password"
        placeholder="Password"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        style={inputStyle}
      />
      {error && <p style={errorStyle}>{error}</p>}
      <button onClick={handleSignUp} style={buttonStyle}>
        Sign Up
      </button>
    </div>
  );
}

// Styles
const formStyle = {
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  gap: '10px',
};

const formHeaderStyle = {
  color: '#ffffff',
};

const inputStyle = {
  width: '80%',
  padding: '10px',
  borderRadius: '5px',
  border: '1px solid #ccc',
  backgroundColor: '#1e1e1e',
  color: '#ffffff',
};

const buttonStyle = {
  padding: '10px 20px',
  borderRadius: '5px',
  border: 'none',
  backgroundColor: '#4caf50',
  color: '#ffffff',
  cursor: 'pointer',
};

const errorStyle = {
  color: '#ff6b6b',
  fontSize: '0.9em',
};

export default SignUp;
